"use client";

import { type TabsProps, Tabs as TabsRoot } from "./tabs";
import { TabsContent, type TabsContentProps } from "./tabs-content";
import { type TabsContextValue, useTabsContext } from "./tabs-context";
import { TabsList, type TabsListProps } from "./tabs-list";
import { TabsTrigger, type TabsTriggerProps } from "./tabs-trigger";

/** Terminal-styled tabbed interface with horizontal and vertical orientation support. */
const Tabs = Object.assign(TabsRoot, {
  List: TabsList,
  Trigger: TabsTrigger,
  Content: TabsContent,
});

export { Tabs, type TabsProps };
export { TabsList, type TabsListProps };
export { TabsTrigger, type TabsTriggerProps };
export { TabsContent, type TabsContentProps };
export { useTabsContext, type TabsContextValue };

"use client";

import {
  Children,
  type ComponentProps,
  isValidElement,
  type ReactNode,
  type Ref,
  useEffect,
  useId,
  useMemo,
  useRef,
  useState,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { useControllableState } from "@/hooks/use-controllable-state";
import type { SegmentedSize, SegmentedVariant } from "@/lib/segmented-variants";
import { useSelectableCollection } from "@/lib/selectable-collection";
import { cn } from "@/lib/utils";
import { warnUnregisteredValue } from "@/lib/warn-unregistered-value";
import { TabsContent } from "./tabs-content";
import { TabsContext } from "./tabs-context";
import { TabsTrigger } from "./tabs-trigger";

/** Props for tabs. */
export interface TabsProps<TValue extends string = string>
  extends Omit<ComponentProps<"div">, "defaultValue" | "onChange"> {
  /** Controlled active tab value. Pair with onChange. */
  value?: TValue;
  /** Fired when the active tab changes. */
  onChange?: (value: TValue) => void;
  /** Initial active tab value for uncontrolled mode. Defaults to the first enabled Trigger. */
  defaultValue?: TValue;
  /** Tab list axis. Switches arrow-key navigation direction and aria-orientation. */
  orientation?: "horizontal" | "vertical";
  /** Visual style applied to triggers and the list. */
  variant?: SegmentedVariant;
  /** Size variant. */
  size?: SegmentedSize;
  /** Automatic activates on focus; manual requires Enter or Space. */
  activationMode?: "automatic" | "manual";
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLDivElement>;
}

/** Props for tab trigger element. */
interface TabTriggerElementProps {
  /** Controlled active tab value. Pair with onChange. */
  value?: string;
  /** Disables interaction. */
  disabled?: boolean;
  /** Tabs.List and Tabs.Content subparts. */
  children?: ReactNode;
}

interface TabSeed {
  enabledValues: string[];
  panelValues: string[];
  triggerValues: string[];
}

// First-render/SSR seed for directly-composed parts: registration effects have
// not run yet, so resolve a sensible selected tab from the static child tree.
// Once items mount, the context registrations below are authoritative and also
// cover parts rendered through consumer wrapper components.
function collectTabSeed(children: ReactNode): TabSeed {
  const seed: TabSeed = { enabledValues: [], panelValues: [], triggerValues: [] };

  Children.forEach(children, (child) => {
    if (!isValidElement<TabTriggerElementProps>(child)) return;
    if (child.type === TabsRoot) return;

    if (child.type === TabsTrigger && typeof child.props.value === "string") {
      seed.triggerValues.push(child.props.value);
      if (!child.props.disabled) seed.enabledValues.push(child.props.value);
      return;
    }

    if (child.type === TabsContent && typeof child.props.value === "string") {
      seed.panelValues.push(child.props.value);
    }

    const nested = collectTabSeed(child.props.children);
    seed.enabledValues.push(...nested.enabledValues);
    seed.panelValues.push(...nested.panelValues);
    seed.triggerValues.push(...nested.triggerValues);
  });

  return seed;
}

/** Terminal-styled tabbed interface with horizontal and vertical orientation support. */
function TabsRoot<TValue extends string = string>(props: TabsProps<TValue>) {
  const {
    value: controlledValue,
    onChange,
    defaultValue,
    orientation = "horizontal",
    variant = "underline",
    size = "sm",
    activationMode = "automatic",
    children,
    className,
    ref,
    ...rest
  } = props;
  const tabsId = useId();
  const rootRef = useRef<HTMLDivElement>(null);
  const composedRef = useComposedRefs(rootRef, ref);
  const {
    items: registeredTriggers,
    registerItem: registerTrigger,
    unregisterItem: unregisterTrigger,
  } = useSelectableCollection(rootRef);
  const {
    items: registeredPanels,
    registerItem: registerPanel,
    unregisterItem: unregisterPanel,
  } = useSelectableCollection(rootRef);
  const seed = useMemo(() => collectTabSeed(children), [children]);
  const triggerValues = useMemo(
    () =>
      registeredTriggers.length ? registeredTriggers.map((item) => item.value) : seed.triggerValues,
    [registeredTriggers, seed.triggerValues],
  );
  const enabledValues = useMemo(
    () =>
      registeredTriggers.length
        ? registeredTriggers.filter((item) => !item.disabled).map((item) => item.value)
        : seed.enabledValues,
    [registeredTriggers, seed.enabledValues],
  );
  const panelValues = useMemo(
    () => (registeredPanels.length ? registeredPanels.map((item) => item.value) : seed.panelValues),
    [registeredPanels, seed.panelValues],
  );
  const [value, setValue] = useControllableState<string>({
    value: "value" in props ? (controlledValue ?? "") : undefined,
    controlled: "value" in props,
    defaultValue: defaultValue ?? "",
    // TValue is a string subtype; downstream context uses string for runtime DOM matching.
    onChange: onChange as ((value: string) => void) | undefined,
  });
  const [focusedValue, setFocusedValue] = useState<string | null>(null);
  const firstEnabledTab = enabledValues[0] ?? "";
  const resolvedValue = enabledValues.includes(value) ? value : firstEnabledTab;

  // A non-empty value that no registered trigger owns silently falls back to the
  // first enabled tab; warn in development so the gap surfaces.
  useEffect(() => {
    if (process.env.NODE_ENV === "production" || value === "") return;
    // Defer to the next frame so a trigger registered by a wrapper component (its
    // registration runs in a layout effect, after this render computed the seed)
    // joins triggerValues before we warn. A change to triggerValues cancels this
    // frame via cleanup and reschedules with the registered set, so the surviving
    // frame always sees the settled values — avoiding a false first-render warning.
    const view = rootRef.current?.ownerDocument.defaultView ?? globalThis;
    const frame = view.requestAnimationFrame(() => {
      warnUnregisteredValue("Tabs", value, triggerValues);
    });
    return () => view.cancelAnimationFrame(frame);
  }, [value, triggerValues]);

  const resolvedFocusedValue =
    focusedValue !== null && enabledValues.includes(focusedValue) ? focusedValue : resolvedValue;

  const contextValue = useMemo(
    () => ({
      tabsId,
      value: resolvedValue,
      tabbableValue: activationMode === "manual" ? resolvedFocusedValue : resolvedValue,
      onChange: setValue,
      onFocusChange: setFocusedValue,
      panelValues,
      triggerValues,
      orientation,
      variant,
      size,
      activationMode,
      registerTrigger,
      unregisterTrigger,
      registerPanel,
      unregisterPanel,
    }),
    [
      tabsId,
      resolvedValue,
      resolvedFocusedValue,
      activationMode,
      setValue,
      panelValues,
      triggerValues,
      orientation,
      variant,
      size,
      registerTrigger,
      unregisterTrigger,
      registerPanel,
      unregisterPanel,
    ],
  );

  return (
    <TabsContext value={contextValue}>
      <div
        ref={composedRef}
        className={cn("flex flex-col", className)}
        data-orientation={orientation}
        {...rest}
      >
        {children}
      </div>
    </TabsContext>
  );
}

export { TabsRoot as Tabs };

"use client";

import { type ComponentProps, type FocusEvent, type KeyboardEvent, useRef } from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { useFloatingIndicator } from "@/hooks/use-floating-indicator";
import { useNavigation } from "@/hooks/use-navigation";
import {
  segmentedContainerVariants,
  segmentedPillIndicatorClass,
  segmentedUnderlineIndicatorClass,
} from "@/lib/segmented-variants";
import { cn } from "@/lib/utils";
import { useTabsContext } from "./tabs-context";

/** Props for tabs list. */
export interface TabsListProps extends ComponentProps<"div"> {
  /** When true, arrow navigation wraps from last to first trigger and vice versa. */
  loop?: boolean;
  /** Fired when arrow navigation reaches the first/last trigger with loop disabled. */
  onNavigationBoundaryReached?: (
    direction: "previous" | "next",
    event: globalThis.KeyboardEvent,
    key: string,
  ) => void;
}

/** Container for tab triggers. */
export function TabsList({
  children,
  className,
  loop = true,
  onBlur,
  onKeyDown,
  onNavigationBoundaryReached,
  ref,
  ...rest
}: TabsListProps) {
  const { orientation, variant, value, tabbableValue, onChange, onFocusChange, activationMode } =
    useTabsContext();

  const containerRef = useRef<HTMLDivElement>(null);
  const composedRef = useComposedRefs(containerRef, ref);

  const handleHighlightChange = (next: string | null) => {
    if (next === null) return;
    if (activationMode === "automatic") onChange(next);
    else onFocusChange(next);
  };

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "tab",
    orientation,
    wrap: loop,
    moveFocus: true,
    scopeToContainer: true,
    highlighted: (activationMode === "automatic" ? value : tabbableValue) || undefined,
    onHighlightChange: handleHighlightChange,
    onNavigationBoundaryReached,
    ...(activationMode !== "automatic" && {
      onEnter: onChange,
      onSelect: onChange,
    }),
  });

  const handleKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
    onKeyDown?.(e);
    if (!e.defaultPrevented) navKeyDown(e);
  };

  const handleBlur = (event: FocusEvent<HTMLDivElement>) => {
    onBlur?.(event);

    const container = containerRef.current;
    const nextTarget = event.relatedTarget;
    const View = container?.ownerDocument.defaultView;
    const focusRemainsInside = Boolean(
      View && nextTarget instanceof View.Node && container?.contains(nextTarget),
    );

    if (!focusRemainsInside) onFocusChange(null);
  };

  // Pill variant: a single absolutely-positioned indicator tracks the active
  // tab's rect. The hook is null-fed when the variant doesn't use a pill, so
  // the observer is never created.
  const pillTargetValue = variant === "pill" ? value : null;
  const pillRect = useFloatingIndicator(containerRef, pillTargetValue);

  const underlineTargetValue = variant === "underline" ? value : null;
  const underlineRect = useFloatingIndicator(containerRef, underlineTargetValue);

  return (
    <div
      ref={composedRef}
      role="tablist"
      data-variant={variant}
      data-orientation={orientation}
      aria-orientation={orientation}
      onBlur={handleBlur}
      onKeyDown={handleKeyDown}
      className={cn(segmentedContainerVariants({ variant, orientation }), className)}
      {...rest}
    >
      {variant === "pill" && pillRect && (
        <span
          aria-hidden="true"
          data-slot="tabs-pill"
          className={segmentedPillIndicatorClass}
          style={{ left: pillRect.left, width: pillRect.width }}
        />
      )}
      {variant === "underline" && underlineRect && (
        <span
          aria-hidden="true"
          data-slot="tabs-underline"
          className={segmentedUnderlineIndicatorClass}
          style={
            orientation === "vertical"
              ? { top: underlineRect.top, height: underlineRect.height, right: 0, width: 1 }
              : { left: underlineRect.left, width: underlineRect.width, bottom: 0, height: 1 }
          }
        />
      )}
      {children}
    </div>
  );
}

"use client";

import {
  type ButtonHTMLAttributes,
  type FocusEvent,
  type MouseEvent,
  type ReactNode,
  type Ref,
  useId,
  useLayoutEffect,
  useRef,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { segmentedItemVariants } from "@/lib/segmented-variants";
import { cn } from "@/lib/utils";
import { getTabPanelId, getTabTriggerId, useTabsContext } from "./tabs-context";

function BracketMarkers({ children }: { children: ReactNode }) {
  return (
    <>
      <span
        aria-hidden="true"
        className="mr-1 text-foreground opacity-0 group-data-[state=active]/segmented-item:opacity-100"
      >
        [
      </span>
      {children}
      <span
        aria-hidden="true"
        className="ml-1 text-foreground opacity-0 group-data-[state=active]/segmented-item:opacity-100"
      >
        ]
      </span>
    </>
  );
}

/** Props for tabs trigger. */
export interface TabsTriggerProps<TValue extends string = string>
  extends Omit<ButtonHTMLAttributes<HTMLButtonElement>, "value" | "disabled"> {
  /** Stable identifier matched against Tabs value and the paired Tabs.Content. */
  value: TValue;
  /** Disables activation and removes the trigger from arrow navigation. */
  disabled?: boolean;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLButtonElement>;
}

/** Clickable tab button. */
export function TabsTrigger<TValue extends string = string>({
  value,
  children,
  className,
  disabled,
  ref,
  onClick,
  onFocus,
  ...rest
}: TabsTriggerProps<TValue>) {
  const {
    tabsId,
    value: selectedValue,
    tabbableValue,
    onChange,
    onFocusChange,
    panelValues,
    variant,
    size,
    orientation,
    registerTrigger,
    unregisterTrigger,
  } = useTabsContext();
  const registrationId = useId();
  const rootRef = useRef<HTMLButtonElement>(null);
  const composedRef = useComposedRefs(rootRef, ref);
  const isActive = selectedValue === value;
  const isTabbable = tabbableValue === value;
  const panelId = panelValues.includes(value) ? getTabPanelId(tabsId, value) : undefined;

  useLayoutEffect(() => {
    registerTrigger(registrationId, value, disabled === true, rootRef.current);
    return () => unregisterTrigger(registrationId);
  }, [registerTrigger, unregisterTrigger, registrationId, value, disabled]);

  const handleClick = (event: MouseEvent<HTMLButtonElement>) => {
    if (disabled) {
      event.preventDefault();
      return;
    }

    onClick?.(event);
    if (!event.defaultPrevented) onChange(value);
  };

  const handleFocus = (event: FocusEvent<HTMLButtonElement>) => {
    onFocus?.(event);
    if (!event.defaultPrevented && !disabled) onFocusChange(value);
  };

  return (
    <button
      {...rest}
      ref={composedRef}
      type="button"
      id={getTabTriggerId(tabsId, value)}
      role="tab"
      aria-selected={isActive}
      aria-controls={panelId}
      aria-disabled={disabled || undefined}
      disabled={disabled}
      tabIndex={isTabbable && !disabled ? 0 : -1}
      data-diffgazer-navigation-item="tab"
      data-value={value}
      data-state={isActive ? "active" : "inactive"}
      data-orientation={orientation}
      onClick={handleClick}
      onFocus={handleFocus}
      className={cn(
        // group/segmented-item lets the bracket markers (and any future
        // decoration) react to data-state without a separate context read.
        "group/segmented-item",
        segmentedItemVariants({ variant, size }),
        className,
      )}
    >
      {variant === "bracket" ? <BracketMarkers>{children}</BracketMarkers> : children}
    </button>
  );
}

"use client";

import { type ComponentProps, useId, useLayoutEffect, useRef } from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { cn } from "@/lib/utils";
import { getTabPanelId, getTabTriggerId, useTabsContext } from "./tabs-context";

/** Props for tabs content. */
export interface TabsContentProps<TValue extends string = string> extends ComponentProps<"div"> {
  /** Stable identifier paired with the matching Tabs.Trigger. */
  value: TValue;
}

/** Panel shown when tab is active. */
export function TabsContent<TValue extends string = string>({
  value,
  children,
  className,
  ref,
  ...rest
}: TabsContentProps<TValue>) {
  const {
    tabsId,
    value: selectedValue,
    orientation,
    triggerValues,
    registerPanel,
    unregisterPanel,
  } = useTabsContext();
  const registrationId = useId();
  const rootRef = useRef<HTMLDivElement>(null);
  const composedRef = useComposedRefs(rootRef, ref);
  const isActive = selectedValue === value;
  const triggerId = triggerValues.includes(value) ? getTabTriggerId(tabsId, value) : undefined;

  useLayoutEffect(() => {
    registerPanel(registrationId, value, false, rootRef.current);
    return () => unregisterPanel(registrationId);
  }, [registerPanel, unregisterPanel, registrationId, value]);

  return (
    <div
      ref={composedRef}
      role="tabpanel"
      id={getTabPanelId(tabsId, value)}
      aria-labelledby={triggerId}
      data-state={isActive ? "active" : "inactive"}
      data-orientation={orientation}
      hidden={!isActive}
      tabIndex={isActive ? 0 : undefined}
      className={cn(
        "mt-2 focus-visible:outline focus-visible:outline-2 focus-visible:outline-ring focus-visible:outline-offset-2",
        className,
      )}
      {...rest}
    >
      {children}
    </div>
  );
}

"use client";

import { createContext, useContext } from "react";
import type { SegmentedSize, SegmentedVariant } from "@/lib/segmented-variants";

function encodeIdPart(value: string): string {
  return encodeURIComponent(value);
}

/** Returns tab trigger id. */
export function getTabTriggerId(tabsId: string, value: string): string {
  return `${tabsId}-tab-${encodeIdPart(value)}`;
}

/** Returns tab panel id. */
export function getTabPanelId(tabsId: string, value: string): string {
  return `${tabsId}-tabpanel-${encodeIdPart(value)}`;
}

/** Context value shared by tabs. */
export interface TabsContextValue {
  /** DOM id for tabs. */
  tabsId: string;
  /** Controlled active tab value. Pair with onChange. */
  value: string;
  /** tabbable value. */
  tabbableValue: string;
  /** Fired when the active tab changes. */
  onChange: (value: string) => void;
  /** Called when focus change occurs. */
  onFocusChange: (value: string | null) => void;
  /** panel values. */
  panelValues: string[];
  /** trigger values. */
  triggerValues: string[];
  /** Tab list axis. Switches arrow-key navigation direction and aria-orientation. */
  orientation: "horizontal" | "vertical";
  /** Visual style applied to triggers and the list. */
  variant: SegmentedVariant;
  /** Size variant. */
  size: SegmentedSize;
  /** Automatic activates on focus; manual requires Enter or Space. */
  activationMode: "automatic" | "manual";
  /** Registers trigger with tabs. */
  registerTrigger: (
    registrationId: string,
    value: string,
    disabled: boolean,
    element: HTMLElement | null,
  ) => void;
  /** Unregisters trigger from tabs. */
  unregisterTrigger: (registrationId: string) => void;
  /** Registers panel with tabs. */
  registerPanel: (
    registrationId: string,
    value: string,
    disabled: boolean,
    element: HTMLElement | null,
  ) => void;
  /** Unregisters panel from tabs. */
  unregisterPanel: (registrationId: string) => void;
}

/** React context backing tabs. */
export const TabsContext = createContext<TabsContextValue | undefined>(undefined);

/** Reads the tabs context. */
export function useTabsContext() {
  const context = useContext(TabsContext);
  if (!context) {
    throw new Error("Tabs compound components must be used within Tabs");
  }
  return context;
}
